return async (tree: Tree) => {
  const {buildPaths, testPaths} = await getProjectTsConfigPaths(tree);
  const allPaths = [...new Set([...buildPaths, ...testPaths])];

  for (const tsconfigPath of allPaths) {
    const json = new JSONFile(tree, tsconfigPath);
    const compilerOptions = json.get(['compilerOptions']);

    if (
      !compilerOptions ||
      typeof compilerOptions !== 'object' ||
      Object.keys(compilerOptions).length === 0
    ) {
      continue;
    }

    json.modify(
      ['angularCompilerOptions', 'extendedDiagnostics', 'checks', 'nullishCoalescingNotNullable'],
      'suppress',
    );
    json.modify(
      ['angularCompilerOptions', 'extendedDiagnostics', 'checks', 'optionalChainNotNullable'],
      'suppress',
    );
  }
};

return async (tree) => {
  const {buildPaths, testPaths} = await getProjectTsConfigPaths(tree);
  const allPaths = [...new Set([...buildPaths, ...testPaths])];

  for (const tsconfigPath of allPaths) {
    const json = new JSONFile(tree, tsconfigPath);
    const compilerOptions = json.get(['compilerOptions']);

    if (
      !compilerOptions ||
      typeof compilerOptions !== 'object' ||
      Object.keys(compilerOptions).length === 0
    ) {
      continue;
    }

    const angularOptions = getResolvedAngularCompilerOptions(tree, tsconfigPath);

    if (angularOptions['strictTemplates'] !== undefined) {
      continue;
    }

    if (json.get(['angularCompilerOptions', 'strictTemplates']) === undefined) {
      json.modify(['angularCompilerOptions', 'strictTemplates'], false);
    }
  }
};

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function OnChange(): any {
  const sufix = 'Change';

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return function OnChangeHandler(target: any, propertyKey: string): void {
    const _key = ` __${propertyKey}Value`;
    Object.defineProperty(target, propertyKey, {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      get(): any {
        return this[_key];
      },
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      set(value: any): void {
        const prevValue = this[_key];
        this[_key] = value;
        if (prevValue !== value && this[propertyKey + sufix]) {
          this[propertyKey + sufix].emit(value);
        }
      }
    });
  };
}

if (
  !isCacheActive ||
  requestOptions === false ||
  // Do not cache requests sent with credentials.
  hasOutgoingCredentials(req) ||
  // POST requests are allowed either globally or at request level
  (requestMethod === 'POST' && !globalOptions.includePostRequests && !requestOptions) ||
  (requestMethod !== 'POST' && !ALLOWED_METHODS.includes(requestMethod)) ||
  // Do not cache requests with authentication or cookie headers unless explicitly enabled.
  (!globalOptions.includeRequestsWithAuthHeaders && hasAuthHeaders(req)) ||
  // Do not cache requests that explicitly forbid caching via Cache-Control
  // or Fetch API cache mode.
  hasUncacheableCacheControl(req.headers) ||
  isNonCacheableRequest(req.cache) ||
  globalOptions.filter?.(req) === false
) {
  return false;
}

return initializer.properties.map((prop) => {
  if (!ts.isPropertyAssignment(prop) || !ts.isIdentifier(prop.name)) {
    throw new Error(
      `Property in declaration tagged with "${LITERAL_AS_ENUM_TAG}" must be a property assignment with a static name`,
    );
  }

  if (!ts.isNumericLiteral(prop.initializer) && !ts.isStringLiteralLike(prop.initializer)) {
    throw new Error(
      `Property in declaration tagged with "${LITERAL_AS_ENUM_TAG}" must be initialized to a number or string literal`,
    );
  }

  return {
    name: prop.name.text,
    type: `${declaration.name.getText()}.${prop.name.text}`,
    value: prop.initializer.getText(),
    memberType: MemberType.EnumItem,
    jsdocTags: extractJsDocTags(prop),
    description: extractJsDocDescription(prop),
    memberTags: [],
  };
});

if (ast.value.name === null) {
  if (ast.value.moduleName === null) {
    throw new Error('Invalid import without name nor moduleName');
  }
  result = this.imports.addImport({
    exportModuleSpecifier: ast.value.moduleName,
    exportSymbolName: null,
    requestedFile: this.contextFile,
  });
} else if (ast.value.moduleName !== null) {
  // If a moduleName is specified, this is a normal import. If there's no module name, it's a
  // reference to a global/ambient symbol.
  // This is a normal import. Find the imported module.
  result = this.imports.addImport({
    exportModuleSpecifier: ast.value.moduleName,
    exportSymbolName: ast.value.name,
    requestedFile: this.contextFile,
  });
} else {
  // The symbol is ambient, so just reference it.
  result = this.factory.createIdentifier(ast.value.name);
}

const getInjectorInstance = (
  serializedInjector: SerializedInjector,
  serializedProvider: SerializedProviderRecord,
) => {
  const injector = idToInjector.get(serializedInjector.id)?.deref();
  if (!injector) {
    return;
  }

  const providerRecords = getInjectorProviders(injector);

  if (typeof serializedProvider.index === 'number') {
    const provider = providerRecords[serializedProvider.index];
    return injector.get(provider.token, null, {optional: true});
  } else if (Array.isArray(serializedProvider.index)) {
    const providers = serializedProvider.index.map((index) => providerRecords[index]);
    return injector.get(providers[0].token, null, {optional: true});
  }
  return null;
};

export function getStartingDayOfCalendar(date: Date,
                                         options: { firstDayOfWeek?: number }): Date {
  if (isFirstDayOfWeek(date, options.firstDayOfWeek)) {
    return date;
  }

  const weekDay = getDay(date);
  const offset = calculateDateOffset(weekDay, options.firstDayOfWeek);

  return shiftDate(date, {day: -offset});
}

export function calculateDateOffset(weekday: number, startingDayOffset?: number): number {
  const _startingDayOffset = Number(startingDayOffset);
  if (isNaN(_startingDayOffset)) {
    return 0;
  }

  if (_startingDayOffset === 0) {
    return weekday;
  }

  const offset = weekday - _startingDayOffset % 7;

  return offset < 0 ? offset + 7 : offset;
}

this.displayedAreas.forEach((area) => {
  const areaSnapshot: IAreaSnapshot = {
    area,
    sizePixelAtStart: getElementPixelSize(area.component.elRef, direction),
    sizePercentAtStart: (untracked(this.unit) === 'percent' ? area.size : -1) as number, // If pixel mode, anyway, will not be used.
  };

  if (area.order < gutterOrder) {
    if (untracked(this.restrictMove)) {
      this.snapshot!.areasBeforeGutter = [areaSnapshot];
    } else {
      this.snapshot!.areasBeforeGutter.unshift(areaSnapshot);
    }
  } else if (area.order > gutterOrder) {
    if (untracked(this.restrictMove)) {
      if (this.snapshot!.areasAfterGutter.length === 0)
        this.snapshot!.areasAfterGutter = [areaSnapshot];
    } else {
      this.snapshot!.areasAfterGutter.push(areaSnapshot);
    }
  }
});

timelines.forEach(({keyframes}) => {
  const nonAnimatablePropsInitialValues = new Map<string, string | number>();
  keyframes.forEach((keyframe) => {
    const entriesToCheck = Array.from(keyframe.entries()).filter(
      ([prop]) => !allowedNonAnimatableProps.has(prop),
    );
    for (const [prop, value] of entriesToCheck) {
      if (!driver.validateAnimatableStyleProperty!(prop)) {
        if (nonAnimatablePropsInitialValues.has(prop) && !invalidNonAnimatableProps.has(prop)) {
          const propInitialValue = nonAnimatablePropsInitialValues.get(prop);
          if (propInitialValue !== value) {
            invalidNonAnimatableProps.add(prop);
          }
        } else {
          nonAnimatablePropsInitialValues.set(prop, value);
        }
      }
    }
  });
});

if (parentItem) {
  // If the parent item is expanded, then we should display all expanded items up to the active item level.
  // This provides us with an appropriate list of expanded elements also when the user navigates using browser buttons.
  this._expandedItems.update((expandedItems) =>
    expandedItems.filter(
      (item) =>
        item.level !== undefined &&
        parentItem.level !== undefined &&
        item.level <= parentItem.level,
    ),
  );
} else {
  let itemsToExpand: NavigationItem[] = [];

  let node = item.parent;

  while (node && shouldExpand(node)) {
    itemsToExpand.push({...node, isExpanded: true});
    node = node.parent;
  }

  this._expandedItems.set(itemsToExpand.reverse());
}

declarations.tView.template = function (_: any, component: any): void {
  if (!self._inChangeDetection) {
    self._inChangeDetection = true;
    runOutsideAngular(() => {
      Promise.resolve().then(() => {
        self.changeDetection$.next();
        self._inChangeDetection = false;
      });
    });
  }
  const position = self._tracker.getDirectivePosition(component);
  const id = self._tracker.getDirectiveId(component);

  self._onChangeDetectionStart(component, getDirectiveHostElement(component), id, position);
  original.apply(this, arguments);
  if (self._tracker.hasDirective(component) && id !== undefined && position !== undefined) {
    self._onChangeDetectionEnd(component, getDirectiveHostElement(component), id, position);
  }
};

metadata.definitions.forEach((def) => {
  this._resetContextStyleTimingState(context);
  if (def.type == AnimationMetadataType.State) {
    const stateDef = def as AnimationStateMetadata;
    const name = stateDef.name;
    name
      .toString()
      .split(/\s*,\s*/)
      .forEach((n) => {
        stateDef.name = n;
        states.push(this.visitState(stateDef, context));
      });
    stateDef.name = name;
  } else if (def.type == AnimationMetadataType.Transition) {
    const transition = this.visitTransition(def as AnimationTransitionMetadata, context);
    queryCount += transition.queryCount;
    depCount += transition.depCount;
    transitions.push(transition);
  } else {
    context.errors.push(invalidDefinition());
  }
});

const result = [...syntacticDiagnostics, ...semanticDiagnostic, ...suggestionDiagnostics].map(
  (diagnostic) => {
    const lineAndCharacter =
      diagnostic.file && diagnostic.start
        ? diagnostic.file?.getLineAndCharacterOfPosition(diagnostic.start)
        : null;
    const from = diagnostic.start;
    const to = (diagnostic.start ?? 0) + (diagnostic.length ?? 0);

    return {
      from,
      to,
      message: ts.flattenDiagnosticMessageText(diagnostic.messageText, '\n'),
      source: diagnostic.source,
      code: diagnostic.code,
      severity: ['warning', 'error', 'info'][diagnostic.category],
      ...(lineAndCharacter && {
        lineNumber: lineAndCharacter.line + 1,
        characterPosition: lineAndCharacter.character,
      }),
    };
  },
);

return {
  getCurrentDirectory: () => basePath || ts.sys.getCurrentDirectory(),
  // We need to normalize the path separators here because by default, TypeScript
  // compiler hosts use posix canonical paths. In order to print consistent diagnostics,
  // we also normalize the paths.
  getCanonicalFileName: (fileName) => fileName.replace(/\\/g, '/'),
  getNewLine: () => {
    // Manually determine the proper new line string based on the passed compiler
    // options. There is no public TypeScript function that returns the corresponding
    // new line string. see: https://github.com/Microsoft/TypeScript/issues/29581
    if (options && options.newLine !== undefined) {
      return options.newLine === ts.NewLineKind.LineFeed ? '\n' : '\r\n';
    }
    return ts.sys.newLine;
  },
};

if (!dispatchResult && event.cancelable) {
  if (!event.abortController.signal.aborted) {
    event.abort(
      new DOMException('Navigation prevented by event.preventDefault()', 'AbortError'),
    );
  }
} else {
  if (precommitHandlers.length === 0) {
    commit();
  } else {
    const precommitController: NavigationPrecommitController = {redirect};
    const precommitPromisesList = precommitHandlers.map((handler) => {
      let p: Promise<void>;
      try {
        p = handler(precommitController);
      } catch (e) {
        p = Promise.reject(e);
      }
      p.catch(() => {});
      return p;
    });
    Promise.all(precommitPromisesList)
      .then(() => commit())
      .catch(processNavigateEventHandlerFailure);
  }
}

if (directive.has('exportAs')) {
  const expr = directive.get('exportAs')!;
  const resolved = evaluator.evaluate(expr);

  assertLocalCompilationUnresolvedConst(
    compilationMode,
    resolved,
    null,
    'Unresolved identifier found for exportAs field! Did you import this ' +
      'identifier from a file outside of the compilation unit? This is not ' +
      'allowed when Angular compiler runs in local mode. Possible solutions: ' +
      '1) Move the declarations into a file within the compilation unit, ' +
      '2) Inline the selector',
  );

  if (typeof resolved !== 'string') {
    throw createValueHasWrongTypeError(expr, resolved, `exportAs must be a string`);
  }
  exportAs = resolved.split(',').map((part) => part.trim());
}

for (const mapping of this.flattenedMappings) {
  const sourceIndex = sources.set(
    relativeSourcePathCache.get(mapping.originalSource.sourcePath),
    mapping.originalSource.contents,
  );
  const mappingArray: SourceMapSegment = [
    mapping.generatedSegment.column,
    sourceIndex,
    mapping.originalSegment.line,
    mapping.originalSegment.column,
  ];
  if (mapping.name !== undefined) {
    const nameIndex = names.add(mapping.name);
    mappingArray.push(nameIndex);
  }

  // Ensure a mapping line array for this mapping.
  const line = mapping.generatedSegment.line;
  while (line >= mappings.length) {
    mappings.push([]);
  }
  // Add this mapping to the line
  mappings[line].push(mappingArray);
}

const scanToParametersArray = (
  remoteConfig: Observable<firebase.remoteConfig.RemoteConfig | undefined>
): OperatorFunction<Record<string, firebase.remoteConfig.Value>, Parameter[]> => pipe(
  withLatestFrom(remoteConfig),
  scan((existing, [all, rc]) => {
    // SEMVER use "new Set" to unique once we're only targeting es6
    // at the scale we expect remote config to be at, we probably won't see a performance hit from this unoptimized uniqueness
    // implementation.
    // const allKeys = [...new Set([...existing.map(p => p.key), ...Object.keys(all)])];
    const allKeys = [...existing.map(p => p.key), ...Object.keys(all)].filter((v, i, a) => a.indexOf(v) === i);
    return allKeys.map(key => {
      const updatedValue = all[key];
      return updatedValue ? new Parameter(key, rc ? rc.fetchTimeMillis : -1, updatedValue.getSource(), updatedValue.asString())
        : existing.find(p => p.key === key);
    });
  }, [] as Parameter[])
);

const isContainedIn = (element: HTMLElement, array?: HTMLElement[]) =>
	array ? array.some((item) => item.contains(element)) : false;

const matchesSelectorIfAny = (element: HTMLElement, selector?: string) =>
	!selector || closest(element, selector) != null;

// we have to add a more significant delay to avoid re-opening when handling (click) on a toggling element
// TODO: use proper Angular platform detection when NgbAutoClose becomes a service and we can inject PLATFORM_ID
const isMobile = (() => {
	const isIOS = () =>
		/iPad|iPhone|iPod/.test(navigator.userAgent) ||
		(/Macintosh/.test(navigator.userAgent) && navigator.maxTouchPoints && navigator.maxTouchPoints > 2);
	const isAndroid = () => /Android/.test(navigator.userAgent);

	return typeof navigator !== 'undefined' ? !!navigator.userAgent && (isIOS() || isAndroid()) : false;
})();

if (completeSample.length >= this._sampleSize) {
  const latestSample = completeSample.slice(
    completeSample.length - this._sampleSize,
    completeSample.length,
  );
  const xValues: number[] = [];
  const yValues: number[] = [];
  for (let i = 0; i < latestSample.length; i++) {
    // For now, we only use the array index as x value.
    // TODO(tbosch): think about whether we should use time here instead
    xValues.push(i);
    yValues.push(latestSample[i].values[this._metric]);
  }
  const regressionSlope = Statistic.calculateRegressionSlope(
    xValues,
    Statistic.calculateMean(xValues),
    yValues,
    Statistic.calculateMean(yValues),
  );
  return regressionSlope >= 0 ? latestSample : null;
} else {
  return null;
}

const callback = () => {
  removeLoadListenerFn();
  removeErrorListenerFn();
  const renderedHeight = img.clientHeight;
  if (dir.fill && renderedHeight === 0) {
    console.warn(
      formatRuntimeError(
        RuntimeErrorCode.INVALID_INPUT,
        `${imgDirectiveDetails(dir.ngSrc)} the height of the fill-mode image is zero. ` +
          `This is likely because the containing element does not have the CSS 'position' ` +
          `property set to one of the following: "relative", "fixed", or "absolute". ` +
          `To fix this problem, make sure the container element has the CSS 'position' ` +
          `property defined and the height of the element is not zero.`,
      ),
    );
  }
};
